use PHPMailer\PHPMailer\PHPMailer;
use PHPMailer\PHPMailer\Exception;

class SecureEmailService {
    private PHPMailer $mailer;
    private array $allowedDomains;

    public function __construct(array $config) {
        $this->mailer = new PHPMailer(true);
        $this->mailer->isSMTP();
        $this->mailer->Host = $config['smtp_host'];
        $this->mailer->SMTPAuth = true;
        $this->mailer->Username = $config['smtp_user'];
        $this->mailer->Password = $config['smtp_pass'];
        $this->mailer->SMTPSecure = PHPMailer::ENCRYPTION_STARTTLS;
        $this->allowedDomains = $config['allowed_from_domains'] ?? [];
    }

    public function sendEmail(string $fromEmail, string $to, string $subject, string $body): bool {
        // Validate sender domain against whitelist
        $fromDomain = substr(strrchr($fromEmail, '@'), 1);
        if (!in_array($fromDomain, $this->allowedDomains, true)) {
            error_log("SECURITY: Rejected sender domain: {$fromDomain}");
            throw new \InvalidArgumentException('Invalid sender domain');
        }

        // Sanitize and validate email
        if (!filter_var($fromEmail, FILTER_VALIDATE_EMAIL)) {
            throw new \InvalidArgumentException('Invalid email format');
        }

        try {
            $this->mailer->setFrom($fromEmail);
            $this->mailer->addAddress($to);
            $this->mailer->Subject = $this->sanitizeHeader($subject);
            $this->mailer->Body = htmlspecialchars($body, ENT_QUOTES, 'UTF-8');
            return $this->mailer->send();
        } catch (Exception $e) {
            error_log("Email failed: " . $e->getMessage());
            return false;
        }
    }

    private function sanitizeHeader(string $header): string {
        return preg_replace('/[\r\n]/', '', $header);
    }
}
```

**Key Security Controls**:
- **Exact version pinning**: Using exact versions (`6.9.1`) prevents unexpected updates with vulnerabilities
- **roave/security-advisories**: Blocks installation of packages with known security issues
- **secure-http enforcement**: Requires HTTPS for package downloads, preventing MITM attacks
- **Input validation**: Email addresses and domains validated before use
- **Stable packages only**: `minimum-stability: stable` prevents dev code installation

Enterprise-grade dependency security requires continuous scanning, automated patching workflows, and incident response procedures. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```php
<?php
// scripts/security-audit.php - Comprehensive dependency scanner
declare(strict_types=1);

namespace App\Security;

use Composer\Semver\Comparator;

class DependencySecurityAuditor {
    private const ADVISORIES_API = 'https://packagist.org/api/security-advisories/';
    private const SEVERITY_WEIGHTS = [
        'critical' => 100,
        'high' => 75,
        'medium' => 50,
        'low' => 25
    ];

    private string $lockFilePath;
    private array $vulnerabilities = [];
    private int $riskScore = 0;

    public function __construct(string $lockFilePath) {
        if (!file_exists($lockFilePath)) {
            throw new \RuntimeException('composer.lock not found');
        }
        $this->lockFilePath = $lockFilePath;
    }

    public function audit(): array {
        $lockContent = json_decode(file_get_contents($this->lockFilePath), true);
        $packages = array_merge(
            $lockContent['packages'] ?? [],
            $lockContent['packages-dev'] ?? []
        );

        $packageVersions = [];
        foreach ($packages as $package) {
            $packageVersions[$package['name']] = $package['version'];
        }

        $advisories = $this->fetchAdvisories(array_keys($packageVersions));

        foreach ($advisories as $packageName => $packageAdvisories) {
            $installedVersion = $packageVersions[$packageName] ?? null;
            if (!$installedVersion) continue;

            foreach ($packageAdvisories as $advisory) {
                if ($this->isVersionAffected($installedVersion, $advisory['affectedVersions'])) {
                    $this->vulnerabilities[] = [
                        'package' => $packageName,
                        'installed_version' => $installedVersion,
                        'advisory_id' => $advisory['advisoryId'],
                        'cve' => $advisory['cve'] ?? 'N/A',
                        'severity' => $advisory['severity'] ?? 'unknown',
                        'title' => $advisory['title'],
                        'link' => $advisory['link'],
                        'affected_versions' => $advisory['affectedVersions'],
                        'patched_versions' => $advisory['patchedVersions'] ?? 'N/A'
                    ];

                    $severity = strtolower($advisory['severity'] ?? 'medium');
                    $this->riskScore += self::SEVERITY_WEIGHTS[$severity] ?? 50;
                }
            }
        }

        return [
            'vulnerabilities' => $this->vulnerabilities,
            'risk_score' => $this->riskScore,
            'scanned_packages' => count($packageVersions),
            'vulnerable_packages' => count(array_unique(array_column($this->vulnerabilities, 'package'))),
            'scan_timestamp' => date('c')
        ];
    }

    private function fetchAdvisories(array $packages): array {
        $ch = curl_init();
        curl_setopt_array($ch, [
            CURLOPT_URL => self::ADVISORIES_API,
            CURLOPT_POST => true,
            CURLOPT_POSTFIELDS => http_build_query(['packages' => $packages]),
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_TIMEOUT => 30,
            CURLOPT_SSL_VERIFYPEER => true
        ]);

        $response = curl_exec($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);

        if ($httpCode !== 200 || !$response) {
            throw new \RuntimeException('Failed to fetch security advisories');
        }

        $data = json_decode($response, true);
        return $data['advisories'] ?? [];
    }

    private function isVersionAffected(string $version, string $constraint): bool {
        // Normalize version (remove 'v' prefix)
        $version = ltrim($version, 'v');

        // Parse constraint ranges
        $ranges = explode('|', $constraint);
        foreach ($ranges as $range) {
            $range = trim($range);
            if ($this->matchesRange($version, $range)) {
                return true;
            }
        }
        return false;
    }

    private function matchesRange(string $version, string $range): bool {
        // Handle >= and < constraints
        if (preg_match('/^>=([\d.]+),<([\d.]+)$/', $range, $matches)) {
            return Comparator::greaterThanOrEqualTo($version, $matches[1]) 
                && Comparator::lessThan($version, $matches[2]);
        }
        return false;
    }
}

// CI/CD Pipeline Integration
class SecurityPipelineIntegration {
    private DependencySecurityAuditor $auditor;
    private array $config;

    public function __construct(string $lockFilePath, array $config = []) {
        $this->auditor = new DependencySecurityAuditor($lockFilePath);
        $this->config = array_merge([
            'fail_on_critical' => true,
            'fail_on_high' => true,
            'max_risk_score' => 100,
            'slack_webhook' => null,
            'pagerduty_key' => null
        ], $config);
    }

    public function runPipelineCheck(): int {
        echo "🔍 Scanning dependencies for vulnerabilities...\n";

        $results = $this->auditor->audit();

        $this->printReport($results);

        // Send alerts for critical issues
        $criticalVulns = array_filter(
            $results['vulnerabilities'],
            fn($v) => strtolower($v['severity']) === 'critical'
        );

        if (!empty($criticalVulns)) {
            $this->sendSecurityAlert($criticalVulns);
        }

        // Determine exit code
        if ($this->config['fail_on_critical'] && !empty($criticalVulns)) {
            echo "\n❌ CRITICAL vulnerabilities found - failing build\n";
            return 2;
        }

        $highVulns = array_filter(
            $results['vulnerabilities'],
            fn($v) => strtolower($v['severity']) === 'high'
        );

        if ($this->config['fail_on_high'] && !empty($highVulns)) {
            echo "\n❌ HIGH severity vulnerabilities found - failing build\n";
            return 1;
        }

        if ($results['risk_score'] > $this->config['max_risk_score']) {
            echo "\n⚠️ Risk score {$results['risk_score']} exceeds threshold\n";
            return 1;
        }

        echo "\n✅ Security scan passed\n";
        return 0;
    }

    private function printReport(array $results): void {
        echo "\n" . str_repeat('=', 60) . "\n";
        echo "DEPENDENCY SECURITY REPORT\n";
        echo str_repeat('=', 60) . "\n\n";
        echo "Packages scanned: {$results['scanned_packages']}\n";
        echo "Vulnerable packages: {$results['vulnerable_packages']}\n";
        echo "Total vulnerabilities: " . count($results['vulnerabilities']) . "\n";
        echo "Risk score: {$results['risk_score']}\n\n";

        foreach ($results['vulnerabilities'] as $vuln) {
            $severityIcon = match(strtolower($vuln['severity'])) {
                'critical' => '🔴',
                'high' => '🟠',
                'medium' => '🟡',
                default => '🟢'
            };

            echo "{$severityIcon} [{$vuln['severity']}] {$vuln['package']}\n";
            echo "   Version: {$vuln['installed_version']}\n";
            echo "   CVE: {$vuln['cve']}\n";
            echo "   Title: {$vuln['title']}\n";
            echo "   Fix: Update to {$vuln['patched_versions']}\n";
            echo "   Link: {$vuln['link']}\n\n";
        }
    }

    private function sendSecurityAlert(array $vulnerabilities): void {
        $message = "🚨 CRITICAL Security Alert\n";
        $message .= count($vulnerabilities) . " critical vulnerabilities detected:\n";

        foreach ($vulnerabilities as $vuln) {
            $message .= "- {$vuln['package']}: {$vuln['cve']}\n";
        }

        // Slack notification
        if ($this->config['slack_webhook']) {
            $this->sendSlackNotification($message);
        }

        // Log to security audit trail
        error_log("SECURITY_ALERT: " . json_encode($vulnerabilities));
    }

    private function sendSlackNotification(string $message): void {
        $payload = json_encode(['text' => $message]);

        $ch = curl_init($this->config['slack_webhook']);
        curl_setopt_array($ch, [
            CURLOPT_POST => true,
            CURLOPT_POSTFIELDS => $payload,
            CURLOPT_HTTPHEADER => ['Content-Type: application/json'],
            CURLOPT_RETURNTRANSFER => true
        ]);
        curl_exec($ch);
        curl_close($ch);
    }
}

