// save-exact=true
// ignore-scripts=true
// audit=true
// fund=false
// package-lock=true

const fs = require('fs');
const crypto = require('crypto');

// Verify package-lock.json integrity before loading dependencies
function verifyLockfileIntegrity() {
  const lockfile = fs.readFileSync('package-lock.json', 'utf8');
  const hash = crypto.createHash('sha512').update(lockfile).digest('base64');
  const expectedHash = process.env.LOCKFILE_HASH;

  if (expectedHash && hash !== expectedHash) {
    console.error('SECURITY ALERT: package-lock.json has been modified!');
    process.exit(1);
  }
  return hash;
}

