**Key Security Controls**:
- **Pin exact versions**: Using `4.18.2` instead of `^4.18.2` prevents automatic upgrades to compromised versions
- **Lock file integrity**: package-lock.json ensures reproducible builds with verified checksums
- **Disable install scripts**: `ignore-scripts=true` prevents malicious postinstall attacks
- **Override vulnerable transitive deps**: The `overrides` field forces secure versions of nested dependencies
- **Continuous auditing**: Regular `npm audit` catches known vulnerabilities before deployment

Transitive dependencies are the hidden attack surface in modern applications. A typical Express.js app has 50+ direct dependencies but 500+ transitive dependencies. The 2024 xz-utils backdoor (CVE-2024-3094) showed how a single compromised transitive dependency can provide root access to systems worldwide.

**PRODUCTION PATTERN**:

```javascript
// dependency-security.js - Comprehensive transitive dependency management
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

class DependencySecurityManager {
  constructor(options = {}) {
    this.allowedRegistries = options.allowedRegistries || ['https://registry.npmjs.org'];
    this.maxDepth = options.maxDepth || 10;
    this.blockedPackages = options.blockedPackages || new Set([
      'event-stream',  // Compromised in 2018
      'flatmap-stream', // Malicious dependency
      'ua-parser-js@0.7.29', // Compromised version
      'ua-parser-js@0.8.0',
      'ua-parser-js@1.0.0',
      'coa@2.0.3',     // Compromised
      'rc@1.2.9'       // Compromised
    ]);
    this.vulnerabilityThreshold = options.vulnerabilityThreshold || 'moderate';
  }

  // Scan all transitive dependencies for known compromised packages
  async scanForCompromisedPackages() {
    const lockfile = JSON.parse(fs.readFileSync('package-lock.json', 'utf8'));
    const packages = lockfile.packages || lockfile.dependencies;
    const findings = [];

    for (const [pkgPath, pkgInfo] of Object.entries(packages)) {
      const pkgName = pkgPath.replace('node_modules/', '');
      const fullName = `${pkgName}@${pkgInfo.version}`;

      // Check against blocklist
      if (this.blockedPackages.has(pkgName) || this.blockedPackages.has(fullName)) {
        findings.push({
          severity: 'CRITICAL',
          package: fullName,
          reason: 'Known compromised package',
          action: 'REMOVE IMMEDIATELY'
        });
      }

      // Verify registry is allowed
      if (pkgInfo.resolved && !this.isAllowedRegistry(pkgInfo.resolved)) {
        findings.push({
          severity: 'HIGH',
          package: fullName,
          reason: `Untrusted registry: ${pkgInfo.resolved}`,
          action: 'Verify package source'
        });
      }

      // Check for missing integrity hashes
      if (!pkgInfo.integrity && pkgPath !== '') {
        findings.push({
          severity: 'MEDIUM',
          package: fullName,
          reason: 'Missing integrity hash',
          action: 'Regenerate lock file'
        });
      }
    }

    return findings;
  }

  isAllowedRegistry(url) {
    return this.allowedRegistries.some(registry => url.startsWith(registry));
  }

  // Generate SBOM (Software Bill of Materials)
  generateSBOM() {
    const lockfile = JSON.parse(fs.readFileSync('package-lock.json', 'utf8'));
    const sbom = {
      bomFormat: 'CycloneDX',
      specVersion: '1.4',
      version: 1,
      metadata: {
        timestamp: new Date().toISOString(),
        component: {
          name: lockfile.name,
          version: lockfile.version,
          type: 'application'
        }
      },
      components: []
    };

    const packages = lockfile.packages || {};
    for (const [pkgPath, pkgInfo] of Object.entries(packages)) {
      if (pkgPath === '') continue;

      sbom.components.push({
        type: 'library',
        name: pkgPath.replace('node_modules/', ''),
        version: pkgInfo.version,
        purl: `pkg:npm/${pkgPath.replace('node_modules/', '')}@${pkgInfo.version}`,
        hashes: pkgInfo.integrity ? [{
          alg: pkgInfo.integrity.split('-')[0].toUpperCase(),
          content: pkgInfo.integrity.split('-')[1]
        }] : []
      });
    }

    return sbom;
  }

  // Run comprehensive security audit
  async runSecurityAudit() {
    const results = {
      timestamp: new Date().toISOString(),
      compromisedPackages: [],
      vulnerabilities: [],
      outdatedPackages: [],
      licenseIssues: []
    };

    // Check for compromised packages
    results.compromisedPackages = await this.scanForCompromisedPackages();

    // Run npm audit
    try {
      execSync('npm audit --json', { encoding: 'utf8' });
    } catch (error) {
      if (error.stdout) {
        const auditResult = JSON.parse(error.stdout);
        results.vulnerabilities = auditResult.vulnerabilities || [];
      }
    }

    // Check for outdated packages
    try {
      const outdated = execSync('npm outdated --json', { encoding: 'utf8' });
      results.outdatedPackages = JSON.parse(outdated || '{}');
    } catch (error) {
      if (error.stdout) {
        results.outdatedPackages = JSON.parse(error.stdout || '{}');
      }
    }

    return results;
  }
}

module.exports = { DependencySecurityManager };
```

