        mapper.enableDefaultTyping();
    }

    @PostMapping("/api/user")
    public String processUser(@RequestBody String jsonInput) {
        try {
            // DANGEROUS: Deserializing untrusted input with default typing
            Object user = mapper.readValue(jsonInput, Object.class);
            return "Processed: " + user.toString();
