<?php
// app/Console/Commands/AutoPatchDependencies.php
// Automated patching for non-breaking security updates

namespace App\Console\Commands;

use Illuminate\Console\Command;
use Symfony\Component\Process\Process;

class AutoPatchDependencies extends Command
{
    protected $signature = 'security:auto-patch {--dry-run}';
    protected $description = 'Automatically apply security patches to dependencies';

    public function handle(): int
    {
        $dryRun = $this->option('dry-run');

        // Get outdated packages with security issues
        $process = new Process(['composer', 'outdated', '--direct', '--format=json']);
        $process->run();

        $outdated = json_decode($process->getOutput(), true);
        $patched = [];

        foreach ($outdated['installed'] ?? [] as $package) {
            if ($this->hasSecurityAdvisory($package['name'])) {
                if ($this->isPatchUpdate($package)) {
                    if (!$dryRun) {
                        $this->applyPatch($package['name']);
                    }
                    $patched[] = $package;
                }
            }
        }

        $this->info(sprintf(
            '%s %d security patches',
            $dryRun ? 'Would apply' : 'Applied',
            count($patched)
        ));

        return Command::SUCCESS;
    }

    private function hasSecurityAdvisory(string $package): bool
    {
        $process = new Process(['composer', 'audit', '--format=json']);
        $process->run();
        $audit = json_decode($process->getOutput(), true);

        return isset($audit['advisories'][$package]);
    }

    private function isPatchUpdate(array $package): bool
    {
        $current = explode('.', $package['version']);
        $latest = explode('.', $package['latest']);

        // Only patch updates (x.y.Z)
        return $current[0] === $latest[0] && $current[1] === $latest[1];
    }

    private function applyPatch(string $package): void
    {
        $process = new Process(['composer', 'update', $package, '--with-dependencies']);
        $process->run();
    }
}
```

**Defense in Depth Layers**:

1. **Pre-commit hooks**: Block commits with known vulnerable dependencies
```bash
#!/bin/bash
# .git/hooks/pre-commit
composer audit --locked
if [ $? -ne 0 ]; then
    echo "Vulnerable dependencies detected. Fix before committing."
    exit 1
fi
```

2. **CI/CD gate**: Prevent deployment of vulnerable code
```yaml
deploy:
  needs: [composer-audit, snyk-scan]
  if: success()
```

3. **Runtime monitoring**: Detect exploitation attempts
```php
<?php
// Middleware to detect exploitation of known vulnerabilities
if (preg_match('/\\x00|%00/', $request->getContent())) {
    Log::channel('security')->alert('Null byte injection attempt', [
        'ip' => $request->ip(),
        'uri' => $request->getRequestUri()
    ]);
    abort(400);
}
```

**Additional Protections**:
- **Dependabot/Renovate**: Automated PR creation for dependency updates
- **SBOM generation**: Track all components with `composer sbom` for compliance
- **Private Packagist**: Mirror packages to prevent supply chain attacks
- **Lock file integrity**: Verify composer.lock hash in CI before deployment
- **Vendor directory monitoring**: Detect unauthorized modifications to vendor files
